import json
baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def extract(data):
    result = {}
    for p in data['projects']:
        pname = p['path'].split('/')[-1]
        for f in p['frameworks']:
            for pkg in f['topLevelPackages']:
                result[(pname, pkg['id'])] = pkg['resolvedVersion']
    return result

